import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import axios from 'axios';
import { Upload, FileText, AlertCircle, CheckCircle, AlertTriangle, XCircle, Search, BookOpen } from 'lucide-react';

const RISK_CONFIG = {
  'Safe':     { cls: 'safe',    badge: 'badge-safe',    icon: <CheckCircle size={14}/>,   label: 'Safe' },
  'Caution':  { cls: 'caution', badge: 'badge-caution', icon: <AlertTriangle size={14}/>, label: 'Caution' },
  'High Risk':{ cls: 'high',    badge: 'badge-high',    icon: <AlertCircle size={14}/>,   label: 'High Risk' },
  'Illegal':  { cls: 'illegal', badge: 'badge-illegal', icon: <XCircle size={14}/>,       label: 'Illegal' },
};

function ConfidenceBar({ value }) {
  const cls = value >= 0.7 ? 'conf-high' : value >= 0.4 ? 'conf-medium' : 'conf-low';
  return (
    <div>
      <div className="flex-between" style={{ fontSize: '0.78rem', color: 'var(--grey)', marginBottom: 3 }}>
        <span>Confidence</span>
        <span>{Math.round(value * 100)}%</span>
      </div>
      <div className="confidence-bar">
        <div className={`confidence-fill ${cls}`} style={{ width: `${value * 100}%` }} />
      </div>
    </div>
  );
}

function ClauseCard({ clause, index }) {
  const [open, setOpen] = useState(false);
  const cfg = RISK_CONFIG[clause.risk_level] || RISK_CONFIG['Caution'];

  return (
    <div className={`clause-card risk-${cfg.cls}`}>
      <div className="clause-header">
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ color: 'var(--grey)', fontSize: '0.8rem' }}>#{index + 1}</span>
          <span className={`badge ${cfg.badge}`}>{cfg.icon} {cfg.label}</span>
        </div>
        <button
          onClick={() => setOpen(!open)}
          style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--grey)', fontSize: '0.8rem' }}
        >
          {open ? '▲ Less' : '▼ More'}
        </button>
      </div>

      <div className="clause-explanation">{clause.explanation}</div>
      <div className="clause-suggestion">→ {clause.suggestion}</div>

      {open && (
        <div style={{ marginTop: 12 }}>
          <div className="clause-text">"{clause.clause_text}"</div>
          <ConfidenceBar value={clause.confidence} />
        </div>
      )}
    </div>
  );
}

function CaseLawCard({ law }) {
  return (
    <div className="case-law-card">
      <div className="case-law-title">{law.title}</div>
      <div className="case-law-meta">
        {law.court && <span>{law.court}</span>}
        {law.year  && <span> · {law.year}</span>}
      </div>
      <div className="case-law-summary">{law.summary}</div>
      {law.url && law.url !== 'https://indiankanoon.org' && (
        <a href={law.url} target="_blank" rel="noreferrer" className="case-law-link mt-4">
          View on Indian Kanoon →
        </a>
      )}
    </div>
  );
}

export default function Analyzer() {
  const [file,       setFile]       = useState(null);
  const [loading,    setLoading]    = useState(false);
  const [analysis,   setAnalysis]   = useState(null);
  const [error,      setError]      = useState('');
  const [question,   setQuestion]   = useState('');
  const [qaLoading,  setQaLoading]  = useState(false);
  const [qaHistory,  setQaHistory]  = useState([]);
  const [sessionId,  setSessionId]  = useState('');
  const [activeTab,  setActiveTab]  = useState('clauses');

  const onDrop = useCallback(accepted => {
    if (accepted[0]) {
      setFile(accepted[0]);
      setAnalysis(null);
      setQaHistory([]);
      setError('');
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'application/pdf': ['.pdf'], 'image/*': ['.jpg','.jpeg','.png'] },
    maxFiles: 1,
  });

  const handleAnalyze = async () => {
    if (!file) return;
    setLoading(true);
    setError('');
    try {
      const form = new FormData();
      form.append('file', file);
      const res = await axios.post('/api/analyze', form, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 120000,  // 2 min timeout
      });
      setAnalysis(res.data);
      setSessionId(res.data.session_id);
    } catch (e) {
      setError(e.response?.data?.detail || 'Analysis failed. Please try again.');
    }
    setLoading(false);
  };

  const handleQuestion = async () => {
    if (!question.trim() || !sessionId) return;
    const q = question.trim();
    setQuestion('');
    setQaLoading(true);
    try {
      const res = await axios.post('/api/qa', { session_id: sessionId, question: q });
      setQaHistory(prev => [...prev, res.data]);
    } catch (e) {
      setQaHistory(prev => [...prev, {
        question: q,
        answer: 'Could not get answer. Please try again.',
        confidence: 0,
        disclaimer: '',
        sources: [],
      }]);
    }
    setQaLoading(false);
  };

  const overallRiskColor = {
    'Safe':     'var(--green)',
    'Moderate': 'var(--orange)',
    'High':     'var(--red)',
    'Critical': '#7F1D1D',
  };

  return (
    <div>
      <h1 className="section-title" style={{ fontSize: '1.4rem', marginBottom: 8 }}>
        📄 Document Analyzer
      </h1>
      <p className="text-grey mb-6">
        Upload a rental agreement, employment contract, legal notice, or FIR.
        Get clause-by-clause risk analysis and ask questions about your document.
      </p>

      {/* Upload */}
      {!analysis && (
        <div className="card mb-6">
          <div {...getRootProps()} className={`upload-zone ${isDragActive ? 'drag-active' : ''}`}>
            <input {...getInputProps()} />
            <div className="upload-zone-icon"><Upload size={36} /></div>
            <div className="upload-zone-text">
              {file
                ? <><strong style={{ color: 'var(--navy)' }}>{file.name}</strong><br/><span>Click Analyze to proceed</span></>
                : <><strong>Click to upload</strong> or drag and drop<br/>PDF, JPG, PNG — max 10 MB</>
              }
            </div>
          </div>
          {file && (
            <div className="flex gap-2 mt-4" style={{ justifyContent: 'center' }}>
              <button className="btn btn-primary" onClick={handleAnalyze} disabled={loading}>
                {loading ? '⏳ Analyzing...' : '🔍 Analyze Document'}
              </button>
              <button className="btn btn-outline" onClick={() => setFile(null)}>Clear</button>
            </div>
          )}
          {error && (
            <div style={{ marginTop: 12, color: 'var(--red)', fontSize: '0.9rem', textAlign: 'center' }}>
              ⚠️ {error}
            </div>
          )}
        </div>
      )}

      {/* Loading */}
      {loading && (
        <div className="card">
          <div className="loading">
            <div className="spinner" />
            <div>
              <strong>Analyzing your document...</strong>
              <div className="text-grey" style={{ marginTop: 4 }}>
                This may take 30-60 seconds depending on document length.
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Results */}
      {analysis && !loading && (
        <>
          {/* Header */}
          <div className="card mb-4">
            <div className="flex-between mb-4">
              <div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  <FileText size={20} color="var(--navy)" />
                  <strong style={{ color: 'var(--navy)', fontSize: '1.05rem' }}>{analysis.document_name}</strong>
                  <span className="tag">{analysis.document_type}</span>
                </div>
                <div className="text-grey" style={{ marginTop: 4 }}>
                  {analysis.total_clauses} clauses analyzed
                </div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontWeight: 700, fontSize: '1.1rem', color: overallRiskColor[analysis.overall_risk] }}>
                  {analysis.overall_risk} Risk
                </div>
                <div className="text-grey" style={{ fontSize: '0.82rem' }}>
                  BNS Compliance: {analysis.compliance_score}/100
                </div>
                <button
                  className="btn btn-outline"
                  style={{ marginTop: 8, fontSize: '0.8rem', padding: '6px 12px' }}
                  onClick={() => { setAnalysis(null); setFile(null); setQaHistory([]); }}
                >
                  Upload New
                </button>
              </div>
            </div>

            {/* Summary */}
            <div className="summary-box">{analysis.summary}</div>

            {/* Risk stats */}
            <div className="risk-overview">
              {[
                { key: 'Safe',      cls: 'safe',    color: 'var(--green)' },
                { key: 'Caution',   cls: 'caution', color: 'var(--orange)' },
                { key: 'High Risk', cls: 'high',    color: 'var(--red)' },
                { key: 'Illegal',   cls: 'illegal', color: '#7F1D1D' },
              ].map(r => (
                <div key={r.key} className={`risk-stat ${r.cls}`}>
                  <div className="risk-stat-number" style={{ color: r.color }}>
                    {analysis.risk_distribution[r.key] || 0}
                  </div>
                  <div className="risk-stat-label">{r.key}</div>
                </div>
              ))}
            </div>

            {/* Recommendations */}
            {analysis.recommendations?.length > 0 && (
              <div>
                <div className="section-title" style={{ fontSize: '0.95rem' }}>Recommendations</div>
                {analysis.recommendations.map((r, i) => (
                  <div key={i} style={{ fontSize: '0.9rem', marginBottom: 6 }}>{r}</div>
                ))}
              </div>
            )}
          </div>

          {/* Tabs */}
          <div style={{ display: 'flex', gap: 4, marginBottom: 16 }}>
            {['clauses', 'qa', 'caselaws'].map(tab => (
              <button
                key={tab}
                className={`btn ${activeTab === tab ? 'btn-primary' : 'btn-outline'}`}
                onClick={() => setActiveTab(tab)}
                style={{ fontSize: '0.85rem', padding: '8px 16px' }}
              >
                {tab === 'clauses'  && <><FileText size={14}/> Clauses ({analysis.clauses?.length})</>}
                {tab === 'qa'       && <><Search size={14}/> Ask Questions</>}
                {tab === 'caselaws' && <><BookOpen size={14}/> Case Laws ({analysis.case_laws?.length})</>}
              </button>
            ))}
          </div>

          {/* Clauses tab */}
          {activeTab === 'clauses' && (
            <div>
              {analysis.clauses?.map((c, i) => (
                <ClauseCard key={i} clause={c} index={i} />
              ))}
            </div>
          )}

          {/* Q&A tab */}
          {activeTab === 'qa' && (
            <div className="card">
              <div className="section-title">Ask about your document</div>
              <p className="text-grey mb-4" style={{ fontSize: '0.88rem' }}>
                Ask anything about this specific document. E.g., "What is the notice period?", "Can the landlord increase rent?", "What happens if I break this contract?"
              </p>

              <div className="qa-input-row">
                <input
                  className="qa-input"
                  placeholder="Ask a question about this document..."
                  value={question}
                  onChange={e => setQuestion(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleQuestion()}
                />
                <button
                  className="btn btn-primary"
                  onClick={handleQuestion}
                  disabled={qaLoading || !question.trim()}
                >
                  {qaLoading ? '...' : 'Ask'}
                </button>
              </div>

              {qaHistory.length === 0 && (
                <div className="text-grey" style={{ textAlign: 'center', padding: '24px', fontSize: '0.88rem' }}>
                  No questions yet. Ask something about your document above.
                </div>
              )}

              {[...qaHistory].reverse().map((qa, i) => (
                <div key={i} className="qa-answer">
                  <div className="qa-question">Q: {qa.question}</div>
                  <div className="qa-text">{qa.answer}</div>
                  <ConfidenceBar value={qa.confidence} />
                  {qa.disclaimer && <div className="qa-disclaimer">{qa.disclaimer}</div>}
                </div>
              ))}
            </div>
          )}

          {/* Case laws tab */}
          {activeTab === 'caselaws' && (
            <div>
              <div className="section-title">Relevant Indian Case Laws</div>
              <p className="text-grey mb-4" style={{ fontSize: '0.88rem' }}>
                Cases retrieved from Indian Kanoon relevant to your document type and risk clauses.
              </p>
              {analysis.case_laws?.length === 0 ? (
                <div className="card text-grey" style={{ textAlign: 'center', padding: 32 }}>
                  No case laws retrieved. Add INDIANKANOON_API_KEY to .env for live results.
                </div>
              ) : (
                analysis.case_laws.map((law, i) => <CaseLawCard key={i} law={law} />)
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}
